import (
	"sort"
)

func solve(code []string, businessLine []string, isActive []bool) []string {
	type coupon struct {
		code        string
		businessLine string
	}

	var validCoupons []coupon

	priority := map[string]int{
		"electronics": 0,
		"grocery":     1,
		"pharmacy":    2,
		"restaurant":  3,
	}

	n := len(code)
	for i := 0; i < n; i++ {
		if !isActive[i] {
			continue
		}

		bl := businessLine[i]
		if _, exists := priority[bl]; !exists {
			continue
		}

		c := code[i]
		if c == "" {
			continue
		}
		validCode := true
		for _, ch := range c {
			if !(ch >= 'a' && ch <= 'z') && 
			   !(ch >= 'A' && ch <= 'Z') && 
			   !(ch >= '0' && ch <= '9') && 
			   ch != '_' {
				validCode = false
				break
			}
		}
		if !validCode {
			continue
		}

		validCoupons = append(validCoupons, coupon{code: c, businessLine: bl})
	}

	sort.Slice(validCoupons, func(i, j int) bool {
		if validCoupons[i].businessLine == validCoupons[j].businessLine {
			return validCoupons[i].code < validCoupons[j].code
		}
		return priority[validCoupons[i].businessLine] < priority[validCoupons[j].businessLine]
	})

	result := make([]string, len(validCoupons))
	for i, c := range validCoupons {
		result[i] = c.code
	}

	return result
}
